#include<bits/stdc++.h>
using namespace std;
int a[10001], b[10001], c[10001], len=1;
void jia(int n) {
	a[1] = 1, b[1] = 2;
	for (int i = 3; i <= n; i++) {
		for (int j = 1; j <= len; j++) {
			c[j] = a[j] + b[j]; }//计算
			for (int j = 1; j <= len; j++) {
				if (c[j] >= 10) {
					c[j + 1] += c[j] / 10;
					c[j] %= 10; //处理进位
					if (j + 1 > len) {
						len++;
					}
				
			}
		}
		for (int j = 1; j <= len; j++) {
			a[j] = b[j];
		}
		for (int j = 1; j <= len; j++) {
			b[j] = c[j];
		}

	}


}
int main() {
    int m,n;
	cin >> m>>n;
	if (n < 3) {
		cout << n-m;
		return 0;
	}
	jia(n-m);
	for (int i = len; i > 0; i--) {
		cout << b[i];
	}
	return 0;
}
